interface InboxBadgeProps {
  count: number
}

export const InboxBadge = ({ count }: InboxBadgeProps) => (
  <button
    type="button"
    aria-label={`Inbox, ${count} unread messages`}
  >
    <span aria-hidden="true">📥</span>
    {count > 0 && (
      <span aria-hidden="true" className="badge">
        {count > 99 ? '99+' : count}
      </span>
    )}
  </button>
)
